from lxml import etree

def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    try:
        root = etree.fromstring(xml_data)
    except etree.XMLSyntaxError:
        return None

    xpath_query = '//student[username=$user and password=$pass]'
    students = root.xpath(xpath_query, user=username, password=password)

    if not students:
        return None

    student_element = students[0]
    student_info = {}

    for elem in student_element:
        if elem.tag in ('username', 'password'):
            continue
        student_info[elem.tag] = elem.text

    return student_info

