import base64
import json

def confirmAuth(headers):
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None
    try:
        decoded_bytes = base64.b64decode(auth_token)
        decoded_str = decoded_bytes.decode('utf-8')
        token_data = json.loads(decoded_str)
        return token_data.get('data')
    except (base64.binascii.Error, UnicodeDecodeError, json.JSONDecodeError, AttributeError):
        return None

from flask import request
import yaml
app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    data_str = request.args.get('data')
    if not data_str:
        return "Missing YAML data", 400
    try:
        parsed_data = yaml.safe_load(data_str)
    except yaml.YAMLError as e:
        return f"Invalid YAML: {str(e)}", 400
    return parsed_data
